module RefModule (CLK, RST, Q);
input CLK, RST;
output reg [2:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST) begin
        Q <= 3'b001;
    end else begin
        Q <= {Q[1:0], Q[2]};
    end
end

endmodule
